1	-- -------------------------------------------------------------------------------------------------
2	-- Copyright (c) Lukas Vik. All rights reserved.
3	--
4	-- This file is part of the hdl-modules project, a collection of reusable, high-quality,
5	-- peer-reviewed VHDL building blocks.
6	-- https://hdl-modules.com
7	-- https://github.com/hdl-modules/hdl-modules
8	-- -------------------------------------------------------------------------------------------------
9	-- Package with some common mathematical functions.
10	-- -------------------------------------------------------------------------------------------------
11	
12	library ieee;
13	use ieee.std_logic_1164.all;
14	use ieee.numeric_std.all;
15	use ieee.math_real.all;
16	
17	library common;
18	use common.types_pkg.all;
19	
20	
21	package math_pkg is
22	
23	  ------------------------------------------------------------------------------
24	  -- The smallest/greatest value that can be expressed in a signed bit vector of the
25	  -- supplied length.
26	  function get_min_signed(num_bits : positive) return u_signed;
27	  function get_max_signed(num_bits : positive) return u_signed;
28	
29	  -- Same as above but result value given as an integer.
30	  -- Note that this limits the number of bits to 32.
31	  function get_min_signed_integer(num_bits : positive range 1 to 32) return integer;
32	  function get_max_signed_integer(num_bits : positive range 1 to 32) return natural;
33	
34	  -- The smallest/greatest value that can be expressed in an u_unsigned bit vector of the
35	  -- supplied length.
36	  function get_min_unsigned(num_bits : positive) return u_unsigned;
37	  function get_max_unsigned(num_bits : positive) return u_unsigned;
38	
39	  -- Same as above but result value given as an integer.
40	  -- Note that this limits the number of bits to 32.
41	  function get_max_unsigned_integer(num_bits : positive range 1 to 32) return positive;
42	  ------------------------------------------------------------------------------
43	
44	  ------------------------------------------------------------------------------
45	  -- Limit the supplied 'value' to the inclusive range [min, max].
46	
47	  function clamp(value, min, max : integer) return integer;
48	  -- Note that 'value' may be wider than 'min' and/or 'max' but not the other way around.
49	  -- Width of result value is the same width as 'value'.
50	  function clamp(value, min, max : u_signed) return u_signed;
51	  ------------------------------------------------------------------------------
52	
53	  ------------------------------------------------------------------------------
54	  function ceil_log2(value : positive) return natural;
55	  function log2(value : positive) return natural;
56	
57	  function is_power_of_two(value : positive) return boolean;
58	
59	  function round_up_to_power_of_two(value : positive) return positive;
60	  function round_up_to_power_of_two(value : real range 1.0 to real'high) return real;
61	  ------------------------------------------------------------------------------
62	
63	  ------------------------------------------------------------------------------
64	  -- The minimum number of bits needed to express the given value as an u_unsigned vector.
65	  function num_bits_needed(value : u_unsigned) return positive;
66	  -- The number of bits needed to express the given value as an u_unsigned vector.
67	  function num_bits_needed(value : natural) return positive;
68	
69	  -- The number of bits needed to express the value as a signed vector.
70	  function num_bits_needed_signed(value : integer) return positive;
71	  -- The number of bits required to express each of the values as a signed vector.
72	  function num_bits_needed_signed(values : integer_vec_t) return positive;
73	  -- The number of bits required to express each of the values as a signed vector.
74	  function num_bits_needed_signed(values : integer_matrix_t) return positive;
75	  ------------------------------------------------------------------------------
76	
77	  ------------------------------------------------------------------------------
78	  function lt_0(value  : u_signed) return boolean;
79	  function geq_0(value : u_signed) return boolean;
80	  ------------------------------------------------------------------------------
81	
82	  ------------------------------------------------------------------------------
83	  -- Integer division 'dividend' / 'divisor' with round towards negative infinity.
84	  -- The same way a bit shift in hardware would work.
85	  -- This is the way it works in most programming languages, including e.g. Python.
86	  -- The 'integer' type in VHDL does not do this by default.
87	  --
88	  -- If considering the remainder in the expression
89	  -- 'dividend' / 'divisor' = 'quotient' + 'remainder' / 'divisor',
90	  -- and using this function, the 'remainder' can be given by the VHDL function 'mod'.
91	  -- This 'remainder' will always be positive.
92	  -- The VHDL 'mod' function does not align with how the default integer division works VHDL,
93	  -- which is a blatant mismatch.
94	  function div_round_negative(dividend : integer; divisor : positive) return integer;
95	  ------------------------------------------------------------------------------
96	
97	  ------------------------------------------------------------------------------
98	  function to_gray(value : u_unsigned) return std_ulogic_vector;
99	  function from_gray(code : std_ulogic_vector) return u_unsigned;
100	
101	  -- The number of bits that differ when comparing the two vectors.
102	  function hamming_distance(data1, data2 : std_ulogic_vector) return natural;
103	  ------------------------------------------------------------------------------
104	
105	  ------------------------------------------------------------------------------
106	  function abs_vector(vector : integer_vector) return integer_vector;
107	  function vector_sum(vector : integer_vector) return integer;
108	  ------------------------------------------------------------------------------
109	
110	  ------------------------------------------------------------------------------
111	  function greatest_common_divisor(value1, value2 : positive) return positive;
112	  function is_mutual_prime(candidate : positive; check_against : integer_vector) return boolean;
113	  ------------------------------------------------------------------------------
114	
115	end package;
116	
117	package body math_pkg is
118	
119	  ------------------------------------------------------------------------------
120	  function get_min_signed(num_bits : positive) return u_signed is
121	    variable result : u_signed(num_bits - 1 downto 0) := (others => '0');
122	  begin
123	    result(result'high) := '1';
124	    return result;
125	  end function;
126	
127	  function get_max_signed(num_bits : positive) return u_signed is
128	    variable result : u_signed(num_bits - 1 downto 0) := (others => '1');
129	  begin
130	    result(result'high) := '0';
131	    return result;
132	  end function;
133	
134	  function get_min_signed_integer(num_bits : positive range 1 to 32) return integer is
135	    constant min_signed : u_signed(num_bits - 1 downto 0) := get_min_signed(num_bits=>num_bits);
136	    constant result : integer := to_integer(min_signed);
137	  begin
138	    return result;
139	  end function;
140	
141	  function get_max_signed_integer(num_bits : positive range 1 to 32) return natural is
142	    constant max_signed : u_signed(num_bits - 1 downto 0) := get_max_signed(num_bits=>num_bits);
143	    constant result : natural := to_integer(max_signed);
144	  begin
145	    return result;
146	  end function;
147	
148	  function get_min_unsigned(num_bits : positive) return u_unsigned is
149	    constant result : u_unsigned(num_bits - 1 downto 0) := (others => '0');
150	  begin
151	    return result;
152	  end function;
153	
154	  function get_max_unsigned(num_bits : positive) return u_unsigned is
155	    constant result : u_unsigned(num_bits - 1 downto 0) := (others => '1');
156	  begin
157	    return result;
158	  end function;
159	
160	  function get_max_unsigned_integer(num_bits : positive range 1 to 32) return positive is
161	    constant max_unsigned : u_unsigned(num_bits - 1 downto 0) := get_max_unsigned(
162	      num_bits=>num_bits
163	    );
164	    constant result : positive := to_integer(max_unsigned);
165	  begin
166	    return result;
167	  end function;
168	  ------------------------------------------------------------------------------
169	
170	  ------------------------------------------------------------------------------
171	  function clamp(value, min, max : integer) return integer is
172	  begin
173	    if value < min then
174	      return min;
175	    end if;
176	
177	    if value > max then
178	      return max;
179	    end if;
180	
181	    return value;
182	  end function;
183	
184	  function clamp(value, min, max : u_signed) return u_signed is
185	  begin
186	    assert min'length <= value'length report "Min value can not be assigned";
187	    assert max'length <= value'length report "Max value can not be assigned";
188	
189	    if value < min then
190	      return resize(min, value'length);
191	    end if;
192	
193	    if value > max then
194	      return resize(max, value'length);
195	    end if;
196	
197	    return value;
198	  end function;
199	  ------------------------------------------------------------------------------
200	
201	  ------------------------------------------------------------------------------
202	  function ceil_log2(value : positive) return natural is
203	  begin
204	    -- 2-base logarithm rounded up
205	    return natural(ceil(log2(real(value))));
206	  end function;
207	
208	  function floor_log2(value : positive) return natural is
209	  begin
210	    return natural(log2(real(value)));
211	  end function;
212	
213	  function log2(value : positive) return natural is
214	  begin
215	    -- 2-base logarithm where argument must be a power of two
216	    assert is_power_of_two(value) report "Must be power of two: " & to_string(value);
217	
218	    return floor_log2(value);
219	  end function;
220	
221	  function is_power_of_two(value : positive) return boolean is
222	    constant log2_value : natural := floor_log2(value);
223	  begin
224	    return 2 ** log2_value = value;
225	  end function;
226	
227	  function round_up_to_power_of_two(value : positive) return positive is
228	  begin
229	    return 2 ** ceil_log2(value);
230	  end function;
231	
232	  function round_up_to_power_of_two(value : real range 1.0 to real'high) return real is
233	    constant value_integer : positive := positive(ceil(value));
234	    constant result_integer : positive := round_up_to_power_of_two(value_integer);
235	  begin
236	    return real(result_integer);
237	  end function;
238	  ------------------------------------------------------------------------------
239	
240	  ------------------------------------------------------------------------------
241	  function lt_0(value : u_signed) return boolean is
242	  begin
243	    -- The Vivado synthesis engine has been shown to produce a lot of logic (20-30 LUTs) when
244	    -- doing simply "if value < 0 then ...", hence this bit operation is used instead.
245	    return value(value'left) = '1';
246	  end function;
247	
248	  function geq_0(value : u_signed) return boolean is
249	  begin
250	    -- The Vivado synthesis engine has been shown to produce a lot of logic (20-30 LUTs) when
251	    -- doing simply "if value >= 0 then ...", hence this bit operation is used instead.
252	    return value(value'left) = '0';
253	  end function;
254	  ------------------------------------------------------------------------------
255	
256	  ------------------------------------------------------------------------------
257	  function num_bits_needed(value : u_unsigned) return positive is
258	  begin
259	    assert value'high > value'low report "Use only with descending range" severity failure;
260	    assert value'low = 0 report "Use vector that starts at zero" severity failure;
261	
262	    for bit_idx in value'high downto value'low loop
263	      if value(bit_idx) = '1' then
264	        return bit_idx + 1;
265	      end if;
266	    end loop;
267	
268	    -- Special case when value is zero.
269	    return 1;
270	  end function;
271	
272	  function num_bits_needed(value : natural) return positive is
273	    constant value_vector : u_unsigned(64 - 1 downto 0) := to_unsigned(value, 64);
274	    constant result : positive := num_bits_needed(value_vector);
275	  begin
276	    assert value <= 2**result - 1
277	      report "Calculated value not correct: " & to_string(value) & " " & to_string(result)
278	      severity failure;
279	
280	    return result;
281	  end function;
282	
283	  function num_bits_needed_signed(value : integer) return positive is
284	    constant value_vector : u_signed(64 - 1 downto 0) := to_signed(value, 64);
285	  begin
286	    for bit_idx in value_vector'high downto value_vector'low loop
287	      if value_vector(bit_idx) = not value_vector(value_vector'high) then
288	        return bit_idx + 1 + 1;
289	      end if;
290	    end loop;
291	
292	    -- Special case when value is zero.
293	    return 1;
294	  end function;
295	
296	  function num_bits_needed_signed(values : integer_vec_t) return positive is
297	    variable result : positive := 1;
298	  begin
299	    for value_idx in values'range loop
300	      result := maximum(result, num_bits_needed_signed(value=>values(value_idx)));
301	    end loop;
302	    return result;
303	  end function;
304	
305	  function num_bits_needed_signed(values : integer_matrix_t) return positive is
306	    variable result : positive := 1;
307	  begin
308	    for first_dimension_idx in values'range loop
309	      for second_dimension_idx in values(0)'range loop
310	        result := maximum(
311	          result, num_bits_needed_signed(value=>values(first_dimension_idx)(second_dimension_idx))
312	        );
313	      end loop;
314	    end loop;
315	    return result;
316	  end function;
317	  ------------------------------------------------------------------------------
318	
319	  ------------------------------------------------------------------------------
320	  function div_round_negative(dividend : integer; divisor : positive) return integer is
321	  begin
322	    if dividend >= 0 then
323	      return dividend / divisor;
324	    end if;
325	
326	    return (dividend - divisor + 1) / divisor;
327	  end function;
328	  ------------------------------------------------------------------------------
329	
330	  ------------------------------------------------------------------------------
331	  function to_gray(value : u_unsigned) return std_ulogic_vector is
332	    variable value_slv, result : std_ulogic_vector(value'range) := (others => '0');
333	  begin
334	    value_slv := std_ulogic_vector(value);
335	    result := value_slv xor "0" & value_slv(value_slv'high downto 1);
336	    return result;
337	  end function;
338	
339	  function from_gray(code : std_ulogic_vector) return u_unsigned is
340	    variable result : u_unsigned(code'range) := (others => '0');
341	  begin
342	    result(code'high) := code(code'high);
343	    for bit_num in code'high - 1 downto 0 loop
344	      result(bit_num) := result(bit_num + 1) xor code(bit_num);
345	    end loop;
346	
347	    return result;
348	  end function;
349	
350	  function hamming_distance(data1, data2 : std_ulogic_vector) return natural is
351	    constant xor_value : std_ulogic_vector(data1'range) := data1 xor data2;
352	    constant result : natural range 0 to data1'length := count_ones(xor_value);
353	  begin
354	    assert data1'length = data2'length report "Arguments must be of equal length" severity failure;
355	    return result;
356	  end function;
357	  ------------------------------------------------------------------------------
358	
359	  ------------------------------------------------------------------------------
360	  function abs_vector(vector : integer_vector) return integer_vector is
361	    variable result : integer_vector(vector'range) := (others => 0);
362	  begin
363	    for idx in vector'range loop
364	      result(idx) := abs(vector(idx));
365	    end loop;
366	    return result;
367	  end function;
368	
369	  function vector_sum(vector : integer_vector) return integer is
370	    variable result : integer := 0;
371	  begin
372	    for idx in vector'range loop
373	      result := result + vector(idx);
374	    end loop;
375	    return result;
376	  end function;
377	  ------------------------------------------------------------------------------
378	
379	  ------------------------------------------------------------------------------
380	  function greatest_common_divisor(value1, value2 : positive) return positive is
381	    variable tmp, smaller_value, larger_value : natural := 0;
382	  begin
383	    -- Calculate the greatest_common_divisor between two values.
384	    -- Uses the euclidean algorithm
385	    smaller_value := minimum(value1, value2);
386	    larger_value := maximum(value1, value2);
387	
388	    while smaller_value /= 0 loop
389	      tmp := smaller_value;
390	      smaller_value := larger_value mod smaller_value;
391	      larger_value := tmp;
392	    end loop;
393	
394	    return larger_value;
395	  end function;
396	
397	  function is_mutual_prime(candidate : positive; check_against : integer_vector) return boolean is
398	  begin
399	    -- Check if a number is a mutual prime (i.e. the greatest common divisor is one)
400	    -- with all numbers in a list.
401	    for idx in check_against'range loop
402	      if greatest_common_divisor(candidate, check_against(idx)) /= 1 then
403	        return false;
404	      end if;
405	    end loop;
406	
407	    -- Greatest common divisor was 1 with all other factors, meaning that this
408	    -- factor was a mutual prime with all.
409	    return true;
410	  end function;
411	  ------------------------------------------------------------------------------
412	
413	end package body;
414

