1	-- -------------------------------------------------------------------------------------------------
2	-- Copyright (c) Lukas Vik. All rights reserved.
3	--
4	-- This file is part of the hdl-modules project, a collection of reusable, high-quality,
5	-- peer-reviewed VHDL building blocks.
6	-- https://hdl-modules.com
7	-- https://github.com/hdl-modules/hdl-modules
8	-- -------------------------------------------------------------------------------------------------
9	-- Truncate a numeric value by removing LSBs and rounding the result.
10	--
11	--
12	-- Rounding details
13	-- ________________
14	--
15	-- The truncation can be seen as removing a number of fractional bits from a fixed-point number.
16	-- The result value will be the closest integer value to the fractional input value.
17	-- If the value is exactly in the middle between two integers, the result will be
18	--
19	-- 1. The integer value of the two that is even, if ``convergent_rounding`` is true.
20	-- 2. The integer value of the two that is closest to positive infinity,
21	--    if ``convergent_rounding`` is false.
22	--
23	-- Convergent rounding is the default rounding mode used in IEEE 754 and comes with some advantages,
24	-- most notably that it yields no bias.
25	-- Convergent mode does consume one more LUT and results in a longer critical path.
26	--
27	--
28	-- Overflow and saturation
29	-- _______________________
30	--
31	-- If the input value is already at the maximum value, and the fractional value is such that a
32	-- rounding upwards should happen, the addition will overflow and the  ``result_overflow`` signal
33	-- will read as 1.
34	-- If the ``enable_saturation`` generic is set to true, the result will instead be saturated to the
35	-- maximum value.
36	--
37	--
38	-- Alternative approach
39	-- ____________________
40	--
41	-- One could sign-extend the input value with one guard bit, add then
42	-- instantiate :ref:`math.saturate_signed` on the result.
43	-- The :ref:`netlist build <math.truncate_round_signed.resource_utilization>` showed,
44	-- however, that this alternative approach results in more LUTs and longer critical path,
45	-- for both wide and narrow words.
46	-- -------------------------------------------------------------------------------------------------
47	
48	library ieee;
49	use ieee.numeric_std.all;
50	use ieee.std_logic_1164.all;
51	
52	library common;
53	use common.types_pkg.all;
54	
55	use work.math_pkg.all;
56	
57	
58	entity truncate_round_signed is
59	  generic (
60	    input_width : positive;
61	    result_width : positive range 1 to input_width;
62	    convergent_rounding : boolean := true;
63	    enable_addition_register : boolean := false;
64	    enable_saturation : boolean := false;
65	    enable_saturation_register : boolean := false
66	  );
67	  port(
68	    clk : in std_ulogic;
69	    --# {{}}
70	    input_valid : in std_ulogic := '0';
71	    input_value : in u_signed(input_width - 1 downto 0);
72	    --# {{}}
73	    result_valid : out std_ulogic := '0';
74	    result_value : out u_signed(result_width - 1 downto 0) := (others => '0');
75	    result_overflow : out std_ulogic := '0'
76	  );
77	end entity;
78	
79	architecture a of truncate_round_signed is
80	
81	begin
82	
83	  ------------------------------------------------------------------------------
84	  passthrough_or_not_gen : if input_width = result_width generate
85	
86	    result_valid <= input_valid;
87	    result_value <= input_value;
88	    result_overflow <= '0';
89	
90	
91	  ------------------------------------------------------------------------------
92	  else generate
93	    constant result_value_max : u_signed(result_value'range) := get_max_signed(
94	      num_bits=>result_value'length
95	    );
96	
97	    signal addition_valid, addition_overflow : std_ulogic := '0';
98	    signal addition_result : u_signed(result_width - 1 downto 0) := (others => '0');
99	  begin
100	
101	    ------------------------------------------------------------------------------
102	    addition_block : block
103	      constant num_lsb_to_remove : positive := input_width - result_width;
104	
105	      constant one_index : natural := num_lsb_to_remove;
106	      constant point_five_index : natural := one_index - 1;
107	      signal one_index_value, point_five_index_value : binary_integer_t := 0;
108	
109	      signal input_value_integer : u_signed(result_width - 1 downto 0) := (others => '0');
110	      signal input_value_integer_is_max : boolean := false;
111	
112	      signal input_value_fractional : u_signed(num_lsb_to_remove - 1 downto 0) := (others => '0');
113	
114	      signal result_int : u_signed(addition_result'range) := (others => '0');
115	      signal overflow_int : std_ulogic := '0';
116	    begin
117	
118	      input_value_integer <= input_value(input_value'high downto num_lsb_to_remove);
119	      input_value_integer_is_max <= input_value_integer = result_value_max;
120	
121	      input_value_fractional <= input_value(input_value_fractional'range);
122	
123	      one_index_value <= to_int(input_value(one_index));
124	      point_five_index_value <= to_int(input_value(point_five_index));
125	
126	
127	      ------------------------------------------------------------------------------
128	      calculate : process(all)
129	        impure function get_fractional_point_five_value return u_signed is
130	          variable result : u_signed(input_value_fractional'range) := (others => '0');
131	        begin
132	          result(input_value_fractional'high) := '1';
133	          return result;
134	        end function;
135	        constant input_value_fractional_point_five : u_signed := get_fractional_point_five_value;
136	
137	        variable value_to_add : binary_integer_t := 0;
138	      begin
139	        if convergent_rounding then
140	          -- There are other ways of formulating this, but this is method seems to yield
141	          -- the lowest resource utilization.
142	          if input_value_fractional = input_value_fractional_point_five then
143	            value_to_add := one_index_value;
144	          else
145	            value_to_add := point_five_index_value;
146	          end if;
147	        else
148	          value_to_add := point_five_index_value;
149	        end if;
150	
151	        result_int <= input_value_integer + value_to_add;
152	        overflow_int <= to_sl(input_value_integer_is_max and value_to_add = 1);
153	      end process;
154	
155	
156	      ------------------------------------------------------------------------------
157	      assign_addition_result : if enable_addition_register generate
158	
159	        addition_valid <= input_valid when rising_edge(clk);
160	        addition_result <= result_int when rising_edge(clk);
161	        addition_overflow <= overflow_int when rising_edge(clk);
162	
163	
164	      ------------------------------------------------------------------------------
165	      else generate
166	
167	        addition_valid <= input_valid;
168	        addition_result <= result_int;
169	        addition_overflow <= overflow_int;
170	
171	      end generate;
172	
173	    end block;
174	
175	
176	    assert enable_saturation or not enable_saturation_register
177	      report "Invalid generic configuration"
178	      severity failure;
179	
180	
181	    ------------------------------------------------------------------------------
182	    saturate_gen : if enable_saturation generate
183	      signal result_int : u_signed(addition_result'range) := (others => '0');
184	    begin
185	
186	      result_int <= result_value_max when addition_overflow else addition_result;
187	
188	
189	      ------------------------------------------------------------------------------
190	      assign_saturation_result : if enable_saturation_register generate
191	
192	        result_valid <= addition_valid when rising_edge(clk);
193	        result_value <= result_int when rising_edge(clk);
194	        result_overflow <= addition_overflow when rising_edge(clk);
195	
196	
197	      ------------------------------------------------------------------------------
198	      else generate
199	
200	        result_valid <= addition_valid;
201	        result_value <= result_int;
202	        result_overflow <= addition_overflow;
203	
204	      end generate;
205	
206	
207	    ------------------------------------------------------------------------------
208	    else generate
209	
210	      result_valid <= addition_valid;
211	      result_value <= addition_result;
212	      result_overflow <= addition_overflow;
213	
214	    end generate;
215	
216	  end generate;
217	
218	end architecture;
219

