39	  main : process
40	
41	    variable rnd : RandomPType;
42	
43	    ------------------------------------------------------------------------------
44	    constant clamp_num_bits : positive := 3;
45	    constant clamp_min_value : integer := get_min_signed_integer(num_bits=>clamp_num_bits);
46	    constant clamp_max_value : integer := get_max_signed_integer(num_bits=>clamp_num_bits);
47	
48	    function clamp_integer(value : integer) return integer is
49	    begin
50	      return clamp(value=>value, min=>clamp_min_value, max=>clamp_max_value);
51	    end function;
52	
53	    function clamp_signed(value : integer) return u_signed is
54	      -- +1 since input 'value' will sometimes be outside of the clamp range.
55	      constant value_signed : u_signed(clamp_num_bits + 1 - 1 downto 0) := to_signed(
56	        value, clamp_num_bits + 1
57	      );
58	      constant min_value_signed : u_signed(clamp_num_bits - 1 downto 0) := to_signed(
59	        clamp_min_value, clamp_num_bits
60	      );
61	      constant max_value_signed : u_signed(clamp_num_bits - 1 downto 0) := to_signed(
62	        clamp_max_value, clamp_num_bits
63	      );
64	      variable result : u_signed(value_signed'range) := (others => '0');
65	    begin
66	      result := clamp(value=>value_signed, min=>min_value_signed, max=>max_value_signed);
67	      return result;
68	    end function;
69	    ------------------------------------------------------------------------------
70	
71	    ------------------------------------------------------------------------------
72	    variable vector : integer_vec_t(0 to 2) := (others => 0);
73	    variable matrix : integer_matrix_t(0 to 1)(0 to 2) := (others => (others => 0));
74	    ------------------------------------------------------------------------------
75	
76	    ------------------------------------------------------------------------------
77	    variable value : u_signed(5 - 1 downto 0);
78	    variable value_slv : u_unsigned(8 - 1 downto 0);
79	    ------------------------------------------------------------------------------
80	
81	    ------------------------------------------------------------------------------
82	    variable integer0, integer1 : integer := 0;
83	    variable real_reference : real := 0.0;
84	    ------------------------------------------------------------------------------
85	
86	    ------------------------------------------------------------------------------
87	    constant some_integer_vector : integer_vector(0 to 3) := (-1, 4, 0, -7);
88	    variable abs_vector_output : integer_vector(0 to 3);
89	    ------------------------------------------------------------------------------
90	
91	  begin
92	    test_runner_setup(runner, runner_cfg);
93	    rnd.InitSeed(get_string_seed(runner_cfg));
94	
95	    if run("test_get_min_max_signed_integer") then
96	      -- Since get_min/max_signed_integer calls get_min/max_signed, only testing like this
97	      -- is enough.
98	
99	      for num_bits in 1 to 31 loop
100	        check_equal(get_min_signed_integer(num_bits=>num_bits), - 2 ** (num_bits - 1));
101	        check_equal(get_max_signed_integer(num_bits=>num_bits), 2 ** (num_bits - 1) - 1);
102	      end loop;
103	
104	      -- The calculation of expected value above goes out of range for this number of bits.
105	      -- Do it manually instead.
106	      check_equal(get_min_signed_integer(num_bits=>32), -2147483648);
107	      check_equal(get_max_signed_integer(num_bits=>32), 2147483647);
108	
109	    elsif run("test_get_max_unsigned_integer") then
110	      for num_bits in 1 to 30 loop
111	        check_equal(get_max_unsigned_integer(num_bits=>num_bits), 2 ** num_bits - 1);
112	      end loop;
113	
114	      -- The calculation of expected value above goes out of range for this number of bits.
115	      -- Do it manually instead.
116	      check_equal(get_max_unsigned_integer(num_bits=>31), 2147483647);
117	
118	    elsif run("test_clamp_integer") then
119	      check_equal(clamp_integer(clamp_min_value - 1), clamp_min_value);
120	      check_equal(clamp_integer(clamp_min_value), clamp_min_value);
121	      check_equal(clamp_integer(clamp_min_value + 1), clamp_min_value + 1);
122	
123	      check_equal(clamp_integer(clamp_max_value - 1), clamp_max_value - 1);
124	      check_equal(clamp_integer(clamp_max_value), clamp_max_value);
125	      check_equal(clamp_integer(clamp_max_value + 1), clamp_max_value);
126	
127	    elsif run("test_clamp_signed") then
128	      check_equal(clamp_signed(clamp_min_value - 1), clamp_min_value);
129	      check_equal(clamp_signed(clamp_min_value), clamp_min_value);
130	      check_equal(clamp_signed(clamp_min_value + 1), clamp_min_value + 1);
131	
132	      check_equal(clamp_signed(clamp_max_value - 1), clamp_max_value - 1);
133	      check_equal(clamp_signed(clamp_max_value), clamp_max_value);
134	      check_equal(clamp_signed(clamp_max_value + 1), clamp_max_value);
135	
136	    elsif run("test_ceil_log2") then
137	      check_equal(ceil_log2(1), 0);
138	
139	      check_equal(ceil_log2(2), 1);
140	
141	      check_equal(ceil_log2(3), 2);
142	      check_equal(ceil_log2(4), 2);
143	
144	      check_equal(ceil_log2(5), 3);
145	      check_equal(ceil_log2(7), 3);
146	      check_equal(ceil_log2(8), 3);
147	
148	      check_equal(ceil_log2(9), 4);
149	
150	    elsif run("test_log2") then
151	      check_equal(log2(1), 0);
152	      check_equal(log2(2), 1);
153	      check_equal(log2(32), 5);
154	      check_equal(log2(64), 6);
155	      check_equal(log2(128), 7);
156	
157	    elsif run("test_is_power_of_two") then
158	      check_true(is_power_of_two(2));
159	      check_true(is_power_of_two(4));
160	      check_true(is_power_of_two(16));
161	
162	      check_false(is_power_of_two(15));
163	      check_false(is_power_of_two(17));
164	
165	    elsif run("test_num_bits_needed_unsigned_integer") then
166	      check_equal(num_bits_needed(0), 1);
167	      check_equal(num_bits_needed(1), 1);
168	      check_equal(num_bits_needed(2), 2);
169	      check_equal(num_bits_needed(3), 2);
170	
171	      check_equal(num_bits_needed(6), 3);
172	      check_equal(num_bits_needed(7), 3);
173	      check_equal(num_bits_needed(8), 4);
174	      check_equal(num_bits_needed(9), 4);
175	
176	    elsif run("test_num_bits_needed_signed_integer") then
177	      check_equal(num_bits_needed_signed(0), 1);
178	
179	      check_equal(num_bits_needed_signed(-1), 1);
180	      check_equal(num_bits_needed_signed(-3), 3);
181	      check_equal(num_bits_needed_signed(-4), 3);
182	
183	      check_equal(num_bits_needed_signed(1), 2);
184	      check_equal(num_bits_needed_signed(3), 3);
185	      check_equal(num_bits_needed_signed(4), 4);
186	
187	    elsif run("test_num_bits_needed_signed_vector") then
188	      check_equal(num_bits_needed_signed(vector), 1);
189	
190	      vector := (7, 6, -1);
191	      check_equal(num_bits_needed_signed(vector), 4);
192	      vector := (0, 8, -1);
193	      check_equal(num_bits_needed_signed(vector), 5);
194	
195	      vector := (-7, 6, -1);
196	      check_equal(num_bits_needed_signed(vector), 4);
197	      vector := (1, -9, -1);
198	      check_equal(num_bits_needed_signed(vector), 5);
199	
200	    elsif run("test_num_bits_needed_signed_matrix") then
201	      check_equal(num_bits_needed_signed(matrix), 1);
202	
203	      matrix := ((7, 6, -1), (0, 8, -1));
204	      check_equal(num_bits_needed_signed(matrix), 5);
205	
206	      matrix := ((-7, 6, -1), (1, -9, -1));
207	      check_equal(num_bits_needed_signed(matrix), 5);
208	
209	    elsif run("test_round_up_to_power_of_two") then
210	      check_equal(round_up_to_power_of_two(1), 1);
211	      check_equal(round_up_to_power_of_two(1.0), 1.0);
212	
213	      check_equal(round_up_to_power_of_two(2), 2);
214	      check_equal(round_up_to_power_of_two(2.0), 2.0);
215	
216	      check_equal(round_up_to_power_of_two(3), 4);
217	      check_equal(round_up_to_power_of_two(4), 4);
218	      check_equal(round_up_to_power_of_two(3.0), 4.0);
219	      check_equal(round_up_to_power_of_two(4.0), 4.0);
220	
221	      check_equal(round_up_to_power_of_two(5), 8);
222	      check_equal(round_up_to_power_of_two(5.0), 8.0);
223	
224	      check_equal(round_up_to_power_of_two(127), 128);
225	      check_equal(round_up_to_power_of_two(128), 128);
226	      check_equal(round_up_to_power_of_two(129), 256);
227	      check_equal(round_up_to_power_of_two(127.0), 128.0);
228	      check_equal(round_up_to_power_of_two(128.0), 128.0);
229	      check_equal(round_up_to_power_of_two(129.0), 256.0);
230	
231	    elsif run("test_num_bits_needed_vector") then
232	      value_slv := "00000000";
233	      check_equal(num_bits_needed(value_slv), 1);
234	
235	      value_slv := "00000001";
236	      check_equal(num_bits_needed(value_slv), 1);
237	
238	      value_slv := "00000010";
239	      check_equal(num_bits_needed(value_slv), 2);
240	
241	      value_slv := "00000011";
242	      check_equal(num_bits_needed(value_slv), 2);
243	
244	      value_slv := "00000100";
245	      check_equal(num_bits_needed(value_slv), 3);
246	
247	    elsif run("test_lt_0") then
248	      value := to_signed(-3, value'length);
249	      check_true(lt_0(value));
250	      value := to_signed(0, value'length);
251	      check_false(lt_0(value));
252	      value := to_signed(3, value'length);
253	      check_false(lt_0(value));
254	
255	    elsif run("test_geq_0") then
256	      value := to_signed(-3, value'length);
257	      check_false(geq_0(value));
258	      value := to_signed(0, value'length);
259	      check_true(geq_0(value));
260	      value := to_signed(3, value'length);
261	      check_true(geq_0(value));
262	
263	    elsif run("test_div_round_negative_hard_coded") then
264	      -- Reference from Python, and from reasoning how it would work in a bit vector in hardware.
265	      check_equal(div_round_negative(5, 4), 1);
266	      check_equal(5 mod 4, 1);
267	      check_equal(div_round_negative(4, 4), 1);
268	      check_equal(4 mod 4, 0);
269	      check_equal(div_round_negative(3, 4), 0);
270	      check_equal(3 mod 4, 3);
271	      check_equal(div_round_negative(2, 4), 0);
272	      check_equal(2 mod 4, 2);
273	      check_equal(div_round_negative(1, 4), 0);
274	      check_equal(1 mod 4, 1);
275	      check_equal(div_round_negative(0, 4), 0);
276	      check_equal(0 mod 4, 0);
277	      check_equal(div_round_negative(-1, 4), -1);
278	      check_equal((-1) mod 4, 3);
279	      check_equal(div_round_negative(-2, 4), -1);
280	      check_equal((-2) mod 4, 2);
281	      check_equal(div_round_negative(-3, 4), -1);
282	      check_equal((-3) mod 4, 1);
283	      check_equal(div_round_negative(-4, 4), -1);
284	      check_equal((-4) mod 4, 0);
285	      check_equal(div_round_negative(-5, 4), -2);
286	      check_equal((-5) mod 4, 3);
287	
288	    elsif run("test_div_round_negative_random_value") then
289	      for test_idx in 0 to 100 loop
290	        integer0 := rnd.Uniform(-100, 100);
291	        integer1 := rnd.Uniform(1, 100);
292	        real_reference := floor(real(integer0) / real(integer1));
293	
294	        check_equal(real(div_round_negative(integer0, integer1)), real_reference);
295	      end loop;
296	
297	    elsif run("test_to_and_from_gray") then
298	      for i in 1 to 2 ** value_slv'length - 2 loop
299	        value_slv := to_unsigned(i, value_slv'length);
300	        check_equal(from_gray(to_gray(value_slv)), value_slv);
301	        -- Verify that only one bit changes when incrementing the input
302	        -- to to_gray
303	        check_equal(hamming_distance(to_gray(value_slv), to_gray(value_slv + 1)), 1);
304	        check_equal(hamming_distance(to_gray(value_slv - 1), to_gray(value_slv)), 1);
305	        check_equal(hamming_distance(to_gray(value_slv - 1), to_gray(value_slv + 1)), 2);
306	      end loop;
307	
308	    elsif run("test_hamming_distance") then
309	      check_equal(hamming_distance("0010", "0010"), 0);
310	      check_equal(hamming_distance("1110", "0010"), 2);
311	      check_equal(hamming_distance("0010", "0011"), 1);
312	      check_equal(hamming_distance("1010", "0011"), 2);
313	
314	    elsif run("test_abs_vector") then
315	      abs_vector_output := abs_vector(some_integer_vector);
316	      for idx in some_integer_vector'range loop
317	        check_equal(abs_vector_output(idx), abs(some_integer_vector(idx)));
318	      end loop;
319	
320	    elsif run("test_vector_sum") then
321	      check_equal(vector_sum((0, 1, -4)), -3);
322	      check_equal(vector_sum((4, 1, 3)), 8);
323	
324	    elsif run("test_greatest_common_divisor") then
325	      check_equal(greatest_common_divisor(6, 3), 3);
326	      check_equal(greatest_common_divisor(7, 3), 1);
327	      check_equal(greatest_common_divisor(7, 1), 1);
328	      check_equal(greatest_common_divisor(8, 15), 1);
329	
330	    elsif run("test_is_mutual_prime") then
331	      check_equal(is_mutual_prime(6, (3, 7)), false);
332	      check_equal(is_mutual_prime(7, (3, 6)), true);
333	      check_equal(is_mutual_prime(7, (1, 5)), true);
334	      check_equal(is_mutual_prime(8, (3, 7)), true);
335	    end if;
336	
337	    test_runner_cleanup(runner);
338	  end process;
339	
340	end architecture;
